class AuthInterceptor(grpc.ServerInterceptor):
    def __init__(self, bypass_patterns=None, auth_validator=None):
        self.bypass_patterns = bypass_patterns or []
        self.auth_validator = auth_validator or self._default_validator
        
    def _default_validator(self, token):
        # Simple token validation - replace with your actual auth logic
        return token and token.startswith("Bearer ")
    
    def _should_bypass_auth(self, method_name):
        for pattern in self.bypass_patterns:
            if re.match(pattern, method_name):
                return True
        return False
    
    def intercept_service(self, continuation, handler_call_details):
        method_name = handler_call_details.method
        
        # Check if this method should bypass authentication
        if self._should_bypass_auth(method_name):
            return continuation(handler_call_details)
        
        # Extract metadata
        metadata = dict(handler_call_details.invocation_metadata)
        auth_token = metadata.get('authorization', '')
        
        # Validate token
        if not self.auth_validator(auth_token):
            def abort(ignored_request, context):
                context.abort(grpc.StatusCode.UNAUTHENTICATED, 'Invalid or missing authentication token')
            
            return grpc.unary_unary_rpc_method_handler(
                abort,
                request_deserializer=lambda x: x,
                response_serializer=lambda x: x
            )
        
        return continuation(handler_call_details)


